UPDATE t_p45929761_bold_move_project.ai_system_prompt
SET content = replace(
  content,
  E'ПРАВИЛО 4 — ПАРЯЩИЙ ПРОФИЛЬ:\n• «парящий» без уточнения → «Flexy FLY 02  с рассеивателем»\n• «ПК-6», «без рассеивателя» → «Парящий ПК-6 без рассеивателя»\n• «FLY 01» → «Flexy FLY 01 без рассеивателем»\nНИКОГДА не добавляй два вида парящего одновременно.\nКоличество = длина указанных стен. Если не уточнил — весь периметр.',
  E'ПРАВИЛО 4 — ПАРЯЩИЙ ПРОФИЛЬ:\nДОБАВЛЯТЬ ТОЛЬКО если монтажник явно произнёс слово «парящий» или «парящий профиль».\nЕСЛИ слова «парящий» НЕ БЫЛО — НЕ ДОБАВЛЯТЬ ни один вид парящего.\nНиша (ПК-14, ПК-12, ПК-15 и т.д.) — это НЕ парящий профиль. При ниши парящий НЕ добавляется.\n• «парящий» без уточнения → «Flexy FLY 02  с рассеивателем»\n• «ПК-6», «без рассеивателя» → «Парящий ПК-6 без рассеивателя»\n• «FLY 01» → «Flexy FLY 01 без рассеивателем»\nНИКОГДА не добавляй два вида парящего одновременно.\nКоличество = длина ТОЛЬКО тех стен где монтажник явно назвал парящий.'
)
WHERE id = 1;